from nicepay import nicepaySNAP
import datetime

nicepaySNAP.setContentType = "Application/JSON"
nicepaySNAP.setPrivateKey = ""
nicepaySNAP.setXClientIDAccessToken = "IONPAYTEST"
nicepaySNAP.setXTimestampAccessToken = datetime.datetime.now().strftime("%Y-%m-%dT%H:%M:%S")+"+07:00"
nicepaySNAP.setBodyAccessToken = {
            "grantType" : "client_credentials",
            "additionalInfo" : {}
            }

nicepaySNAP.genAccessToken()